head.script:
// 전역변수 선언
scwin.saveFlag;
scwin.selRow;

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSZZ1800000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 로그인한 사용자 ID 변수설정
	scwin.usrId = comLib.getUsrId();
	scwin.setAdminDivCd();
};

/**
 * 관리자구분코드를 조회한다.
 * @param
 * @return
 */
scwin.setAdminDivCd = function() {
	var requestData = {};
	// 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
	requestData.dmaInqireParam = {"clsCd" : "SCM_0246", "useYn" : "Y"};

	var option = {
		action : "sc/cmmncd/retrieveCmmnCd.do",
		reqData : requestData,
		resData : dltAdminDivList,
		success : "scwin.retrieveAdminDivCdCallback",
		isShowMeg : false
	};
	ajaxLib.requestAjaxSyncCode($p, option);
};

/**
 * 조회 CallBack 실행
 * @param
 * @return
 */
scwin.retrieveAdminDivCdCallback = function () {
	// 사용자 권한 부여된 시스템구분 설정
	scwin.setUsrAthrSysCd();
};

/**
 * 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
 * @param
 * @return
 */
scwin.setUsrAthrSysCd = function () {
	var requestData = {};

	// 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
	if (comLib.getSysDivCd() != "SCM") {
		requestData.data = {"usrId" : scwin.usrId, "sysDivCd" : "SCM_0000", "cmmnCd" : comLib.getSysDivCd()};
	} else {
		requestData.data = {"usrId" : scwin.usrId, "sysDivCd" : "SCM_0000"};
	}

	var option = {
		action : "sc/authmng/retrieveAthrSysDivCd.do",
		reqData : requestData,
		resData : dltSysDivCdList,
		success : "scwin.retrieveAthrSysDivCdCallback",
		isShowMeg : false
	};
	ajaxLib.requestAjaxSyncCode($p, option);
};

/**
 * 조회 CallBack 실행
 * @param <Object> resBody
 * @return
 */
scwin.retrieveAthrSysDivCdCallback = function (resBody, e) {
	if (dltSysDivCdList.getRowCount() == 0) {
		// 시스템관리자만 접근이 가능합니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00343"), "utilLib.winContainerClose");
		return;
	}

	txtCnt1.setValue(dltSysDivCdList.getRowCount());

	if (dltSysDivCdList.getRowCount() == 0) {
		comLib.alert($p, utilLib.getMessage("SCM.SYS.00003"));
		return;
	}

	// 화면 오픈시 자동조회를 한다.
	comLib.setEnterKeyEvent(grpInqire, scwin.btnInqire_onclick);
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 및 그리드 초기화를 한다.
 * @param
 * @return
 */
scwin.btnClear_onclick = function() {
	dmaInqireParam.reset();

	dmaInqireParam.set("usrId", "");
	dmaInqireParam.set("usrNm", "");

	txtCnt2.setValue("0");

	scwin.btnInqire_onclick();
};

/**
 * 시스템구분별 사용자 목록을 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	if (dltSysDivCdList.getRowCount() == 0) {
		comLib.alert($p, utilLib.getMessage("SCM.SYS.00003"));
		return;
	}

	if (dmaInqireParam.get("intnSysDivCd") == "") {
		dmaInqireParam.set("intnSysDivCd", dltSysDivCdList.getCellData(0, "sysDivCd"));
	}

	var requestData = {};
	requestData.dmaInqireParam = dmaInqireParam.getJSON();

	var option = {
		action : "sc/authmng/retrieveUsrSysAthr.do",
		reqData : requestData,
		resData : dltUsrSysDivList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.inqireCallback = function(resBody) {
	if (resBody.message.code == "success") {
		txtCnt2.setValue(dltUsrSysDivList.getRowCount());

		for (var idx = 0; idx < dltUsrSysDivList.getRowCount(); idx++) {
			grdUsrSysDivList.setCellReadOnly(idx, "adminDivCd", true);
			grdUsrSysDivList.setCellDisabled(idx, "inqireUsr", true);
		}
	} else {
		comLib.alert($p, "fail");
		txtCnt2.setValue("0");
		return;
	}

	grdUsrSysDivList.setHeaderValue("chkHeader","0");
};

/**
 * 시스템구분 그리드에서 시스템구분을 선택 시 해당 시스템구분으로 설정되어 있는 사용자목록을 조회한다.
 * @param <Int> row
 * @param <Int> col
 * @return
 */
scwin.grdSysDivCdList_oncellclick = function(row, col) {
	var strIntnSysDivCd = dltSysDivCdList.getCellData(row, "sysDivCd");

	dmaInqireParam.set("intnSysDivCd", strIntnSysDivCd);

	scwin.btnInqire_onclick();
};

/**
 * 시스템구분별 사용자 정보 등록/수정한다.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	if (dltUsrSysDivList.getModifiedData() == "") {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		return;
	}

	scwin.saveFlag = "U";
	scwin.saveCnfirm();
};

/**
 * 저장, 삭제 여부를 물어본다.
 * @param
 * @return
 */
scwin.saveCnfirm = function() {
	if (scwin.saveFlag != "D") {
		// 저장할것인지 confirm
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00239"), "scwin.saveConfirmCallback");
	}
	else {
		// 삭제할것인지 confirm
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00251"), "scwin.saveConfirmCallback");
	}
};

/**
 * 수정/저장 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var requestData = {};
	requestData.dltUsrSysDivList = dltUsrSysDivList.getModifiedJSON();

	var option = {
		action : "sc/authmng/saveUsrSysAthr.do",
		reqData : requestData,
		success : "scwin.saveUsrSysAthrCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 수정/저장 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.saveUsrSysAthrCallback = function(resBody) {
	//comLib.alert($p, resBody.message.code_name);
	if (scwin.saveFlag == "D") {
		// 삭제되었습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00328"));
	} else {
		// 저장되었습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00327"));
	}

	scwin.btnInqire_onclick();
};

/**
 * 작업중이던 내용을 취소한다.
 * @param
 * @return
 */
scwin.btnCancl_onclick = function() {
	// 작업중이던 dataMap을 초기화한다.
	scwin.btnClear_onclick();
};

/**
 * 화면목록에서 선택한 화면을 삭제한다.
 * @param
 * @return
 */
scwin.btnDel_onclick = function() {
	if (dltUsrSysDivList.getModifiedData() == "") {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		return;
	}

	scwin.saveFlag = "D";

	comLib.removeGridView(grdUsrSysDivList);

	scwin.saveCnfirm();
};

/**
 * 시스템구분코드 변경시 자동 체크되도록 한다.
 * @param <Object> info
 * @return
 */
scwin.grdUsrSysDivList_onviewchange = function(info) {
	var rowIndex = info.rowIndex;
	var colIndex = info.colIndex;
	var oldValue = info.oldValue;
	var newValue = info.newValue;

	// 선택 컬럼에 체크시 시스템구분명이 자동 기재되도록 한다.
	if (colIndex == '0') {
		if(newValue == '1') {
			// 시스템구분 목록에서 선택을 한 경우가 아니면 시스템구분을 먼저 선택을 하도록 한다.
			if (dmaInqireParam.get("intnSysDivCd") == "") {
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00072", "시스템구분"));
				return;
			}

			if (dltUsrSysDivList.getCellData(rowIndex, "intnSysDivNm") == "") {
				dltUsrSysDivList.setCellData(rowIndex, "intnSysDivCd", dmaInqireParam.get("intnSysDivCd"));

				// 신규로 등록되는 정보임.
				dltUsrSysDivList.modifyRowStatus(rowIndex, "C");
			}
		} else {
			if (dltUsrSysDivList.getCellData(rowIndex, "intnSysDivNm") == "") {
				dltUsrSysDivList.setCellData(rowIndex, "intnSysDivCd", "");
			}
		}
	} else if (colIndex == '1') {
		if (oldValue != newValue) {
			dltUsrSysDivList.setCellData(rowIndex, "chk", '1');
		}
		if (dltUsrSysDivList.getCellData(rowIndex, "intnSysDivNm") == "") {
			dltUsrSysDivList.modifyRowStatus(rowIndex, "C");
		}
	}
};

/**
 * 시스템구분명을 자동으로 설정하도록 한다.(그리드 헤더에서 체크시)
 * @param <String> headerId
 * @return
 */
scwin.grdUsrSysDivList_onheaderclick = function(headerId) {
	// 시스템구분 목록에서 선택을 한 경우가 아니면 시스템구분을 먼저 선택을 하도록 한다.
	if (headerId == "chkHeader" && dmaInqireParam.get("intnSysDivCd") == "") {
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00072", "시스템구분"));
		return;
	}

	if (headerId == "chkHeader") {
		var strSysDivCd = dmaInqireParam.get("intnSysDivCd");

		for (var idx = 0; idx < dltUsrSysDivList.getRowCount(); idx++) {
			var chkYn = dltUsrSysDivList.getCellData(idx, "chk");
			var strSysNm = dltUsrSysDivList.getCellData(idx, "intnSysDivNm");

			// 체크여부가 true이면서 시스템구분코드가 지정 안되어 있을 경우 자동으로 시스템구분코드를 지정한다.
			if (chkYn == '1' && strSysNm == "") {
				dltUsrSysDivList.setCellData(idx, "intnSysDivCd", strSysDivCd);

				// 신규로 등록되는 정보임.
				dltUsrSysDivList.modifyRowStatus(idx, "C");
			// 체크여부가 false이면서 시스템구분코드가 지정 안되어 있을 경우 체크를 해지하면서 시스템구분코드를 null로 대체한다.
			} else if (chkYn == '0' && strSysNm == "") {
				dltUsrSysDivList.setCellData(idx, "intnSysDivCd", "");
			} else {
				dltUsrSysDivList.setCellData(idx, "chk", '0');
			}
		}
	}
};

/**
 * 사용자 조회
 */
scwin.btnInqireUsr_onclick = function() {
	var url = comLib.HRM_POP_URL + "/ui/hrm/zz/searchmng/HRMZZ20000001.xml";

	// 팝업창 옵션
	var option = {
		popupID : "HRMZZ20000001",
		width : 800,
		height : 500,
		title : "사용자 검색"
	};

	var strEnc = comLib.dataDecEnc(utilLib.getDate(), "E"); // 암호화 키값
	var usrInfo; // 세션정보 및 윈도우 타이틀

	usrInfo = JSON.stringify(comLib.getUserInfo4Param(strEnc, encodeURI(option.title)));

	var jsonObj = {
		// 필수값
		userInfo : usrInfo,
		closeCallbackFncName : "scwin.inqireUsrCallback",
		popupId : option.popupID
	};

	comLib.openPostWinPopup($p, url, option, jsonObj);
};

/**
* 사용자 검색 CallBack 실행
*/
scwin.inqireUsrCallback = function(returnValue, popupId) {
	var selectedOrg = returnValue;
	dmaInqireParam.set("usrId", selectedOrg.usrId);
	dmaInqireParam.set("usrNm", selectedOrg.usrNm);
};

/**
 * 사용자 조회
 */
scwin.btnInqireUsr1_onclick = function() {
	scwin.selRow = grdUsrSysDivList.getFocusedRowIndex();

	var url = comLib.HRM_POP_URL + "/ui/hrm/zz/searchmng/HRMZZ20000001.xml";

	//팝업창 옵션
	var option = {
		popupID : "HRMZZ20000001",
		width : 800,
		height : 500,
		title : "사용자 검색"
	};

	var strEnc = comLib.dataDecEnc(utilLib.getDate(), "E"); // 암호화 키값
	var usrInfo; // 세션정보 및 윈도우 타이틀
	usrInfo = JSON.stringify(comLib.getUserInfo4Param(strEnc, encodeURI(option.title)));

	var jsonObj = {
		// 필수값
		userInfo : usrInfo,
		closeCallbackFncName : "scwin.inqireUsr1Callback",
		popupId : option.popupID
	};

	comLib.openPostWinPopup($p, url, option, jsonObj);
};

/**
* 사용자 검색 CallBack 실행
*/
scwin.inqireUsr1Callback = function(returnValue, popupId) {
	var selectedOrg = returnValue;
	dltUsrSysDivList.setCellData(scwin.selRow, "usrId", selectedOrg.usrId);
	dltUsrSysDivList.setCellData(scwin.selRow, "usrNm", selectedOrg.usrNm);
};

/**
* 사용자 목록에 행추가를 하여 정보 등록을 한다.
*/
scwin.btnAddRow_onclick = function() {
	var insertIndex = dltUsrSysDivList.insertRow();
	var usrNm = dmaInqireParam.get("usrNm");
	var intnSysCd = dmaInqireParam.get("intnSysDivCd");

	if (intnSysCd == "") {
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00072", "시스템구분"));
		return;
	}

	grdUsrSysDivList.setFocusedCell(insertIndex, "intnSysDivCd");
/*
	if(scwin.isAdmin != "ADMIN") {
		dltUsrSysDivList.setCellData(insertIndex, "intnSysDivCd", intnSysCd);
		dltUsrSysDivList.setCellData(insertIndex, "usrId", dmaInqireParam.get("usrId"));
		dltUsrSysDivList.setCellData(insertIndex, "usrNm", dmaInqireParam.get("usrNm"));

		grdUsrSysDivList.setColumnReadOnly("usrId", true);
		grdUsrSysDivList.setColumnDisabled("inqireUsr", true);
		grdUsrSysDivList.setColumnReadOnly("usrNm", true);
	} else {
		dltUsrSysDivList.setCellData(insertIndex, "intnSysDivCd", intnSysCd);
		dltUsrSysDivList.setCellData(insertIndex, "usrId", "");
		dltUsrSysDivList.setCellData(insertIndex, "usrNm", "");

		grdUsrSysDivList.setColumnReadOnly("usrId", false);
		grdUsrSysDivList.setColumnDisabled("inqireUsr", false);
		grdUsrSysDivList.setColumnReadOnly("usrNm", false);

		scwin.btnInqireUsr1_onclick();
	}
*/
	dltUsrSysDivList.setCellData(insertIndex, "intnSysDivCd", intnSysCd);
	dltUsrSysDivList.setCellData(insertIndex, "usrId", dmaInqireParam.get("usrId"));
	dltUsrSysDivList.setCellData(insertIndex, "usrNm", dmaInqireParam.get("usrNm"));
	dltUsrSysDivList.setCellData(insertIndex, "useYn", "Y");
};

/**
 * 개별 행삭제를 할 경우 사용한다.
 * @param
 * @return
 */
scwin.btnDelRow_onclick = function() {
	var rowIndex = grdUsrSysDivList.getFocusedRowIndex();
	var rowStatus = dltUsrSysDivList.getRowStatus(rowIndex);

	if (rowStatus != "C") {
		dltUsrSysDivList.deleteRow(rowIndex);
	} else {
		dltUsrSysDivList.removeRow(rowIndex);
	}
};

scwin.ibxUsrNm_onviewchange = function(info) {
	if(info.newValue == "") {
		dmaInqireParam.set("usrId", "");
		dmaInqireParam.set("usrNm", "");
	}
};
